def bc(v):
    """Consistent colour encoding: high=dark teal, mid=teal, low=amber, very low=coral"""
    if v>=70: return "#065F46"   # Dark teal, high
    if v>=50: return "#10B981"   # Teal mid, good
    if v>=30: return "#34D399"   # Teal light, moderate
    if v>=15: return "#F59E0B"   # Amber, low
    return "#EF4444"             # Coral, very low

