# ── Loading animation (shows once per session) ─────────────────────────────────
if "loaded" not in st.session_state:
    st.markdown("""
    <div class="loader">
      <div class="loader-title">WorkShift Canada</div>
      <div class="loader-sub">Canada · 2020–2025</div>
      <div class="loader-bar"><div class="loader-fill"></div></div>
    </div>
    """, unsafe_allow_html=True)
    time.sleep(1.8)
    st.session_state.loaded = True

# ── Session state ──────────────────────────────────────────────────────────────
# Valid tab + page values for URL routing
_VALID_TABS  = ["overview","industry","productivity","geography","forecast","story"]
_VALID_PAGES = ["cover","dashboard","guide"]
_VALID_LANGS = ["EN","FR"]

# Read URL query params ONCE on first run, then session state takes over
_qp = st.query_params

if "page" not in st.session_state:
    _p = _qp.get("page", "cover")
    st.session_state.page = _p if _p in _VALID_PAGES else "cover"
if "tab" not in st.session_state:
    _t = _qp.get("tab", "overview")
    st.session_state.tab = _t if _t in _VALID_TABS else "overview"
    # If tab was in URL, start directly on dashboard
    if _t in _VALID_TABS and "page" in _qp is False and st.session_state.page == "cover":
        st.session_state.page = "dashboard"
if "lang" not in st.session_state:
    _l = _qp.get("lang", "EN")
    st.session_state.lang = _l if _l in _VALID_LANGS else "EN"
if "geo_view" not in st.session_state:
    _gv = _qp.get("geo_view", "provinces")
    st.session_state.geo_view = _gv if _gv in ("provinces","cities") else "provinces"
if "compare_mode" not in st.session_state:
    st.session_state.compare_mode = False

# Keep URL in sync with session state so users can bookmark / share
def _sync_url():
    st.query_params["page"]     = st.session_state.page
    st.query_params["tab"]      = st.session_state.tab
    st.query_params["lang"]     = st.session_state.lang
    st.query_params["geo_view"] = st.session_state.geo_view

_sync_url()

