CHART_TXT  = "#1A202C"                       # chart text (dark, Streamlit handles dark mode)
CHART_GRID = "rgba(0,0,0,0.07)"              # gridline opacity
CHART_BG   = "rgba(0,0,0,0)"                 # transparent chart background
FONT_UI    = "Inter"                          # primary UI font
FONT_EDIT  = "'Playfair Display', serif"      # editorial / cover / story
