# ── Insights component ─────────────────────────────────────────────────────────
def render_insights(points_or_key):
    """Render key insights box. Pass a translation key string (e.g. 'ins_overview')
    or a list of HTML strings. Title auto-translates based on session language."""
    lang  = st.session_state.get("lang", "EN")
    title = T[lang].get("insights_lbl", "💡 Key insights")
    # Accept either a T[] key string or a direct list
    if isinstance(points_or_key, str):
        points = T[lang].get(points_or_key, T["EN"].get(points_or_key, []))
    else:
        points = points_or_key
    rows = "".join([
        f'<div class="insight-row"><div class="insight-dot"></div>'
        f'<div class="insight-text">{p}</div></div>'
        for p in points
    ])
    st.markdown(
        f'<div class="insights"><div class="insights-title">{title}</div>{rows}</div>',
        unsafe_allow_html=True
    )

