# SHARED COMPONENTS, reusable across all tabs
# ═══════════════════════════════════════════════════════════════════════════════

def chart_theme(fig, height=340, barmode=None, legend_h=True):
    """Apply consistent Plotly layout to any figure.
    Eliminates 11 repeated update_layout() blocks across the dashboard."""
    layout_args = dict(
        height=height,
        margin=dict(l=0, r=0, t=48 if legend_h else 10, b=0),
        paper_bgcolor=CHART_BG,
        plot_bgcolor=CHART_BG,
        font=dict(family=FONT_UI, size=12, color=CHART_TXT),
        xaxis=dict(showgrid=True, gridcolor=CHART_GRID),
        yaxis=dict(showgrid=True, gridcolor=CHART_GRID),
        showlegend=bool(legend_h),
    )
    if barmode:
        layout_args["barmode"] = barmode
    if legend_h:
        layout_args["legend"] = dict(
            orientation="h", x=0, y=1.10,
            font=dict(size=11), bgcolor="rgba(0,0,0,0)")
    fig.update_layout(**layout_args)
    return fig

def render_kpi(label, value, delta="", cls="kn", size="34px"):
    """Render a single KPI card. Call inside a st.columns() block.
    cls: 'ku' (green/up), 'kd' (red/down), 'kn' (neutral/grey)"""
    delta_html = f'<div class="{cls}">{delta}</div>' if delta else ""
    st.markdown(f'''<div class="kpi">
      <div class="kl">{label}</div>
      <div class="kv" style="font-size:{size};">{value}</div>
      {delta_html}
    </div>''', unsafe_allow_html=True)

def render_source(text):
    """Render a consistent source citation line under any chart."""
    st.markdown(f'<div class="src">{text}</div>', unsafe_allow_html=True)

def render_section(title):
    """Render a section label (uppercase, muted, consistent spacing)."""
    st.markdown(f'<div class="sec">{title}</div>', unsafe_allow_html=True)

def render_spacer(px=20):
    """Add vertical whitespace."""
    st.markdown(f"<div style='height:{px}px'></div>", unsafe_allow_html=True)

